module RefModule(
  input clk,
  input rst_n,
  input [7:0] duty_cycle,
  output reg pwm_out
);

  reg [7:0] obf_counter;

  always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
      obf_counter <= 8'b0;
      pwm_out <= 0;
    end
    else begin
      obf_counter <= obf_counter + 1;
      if (obf_counter < duty_cycle)
        pwm_out <= 1;
      else
        pwm_out <= 0;
    end
  end

endmodule
